#nullable enable // autogenerated

using System.Collections.Generic;
using System.Linq;
using MVZ2Logic.Options;
using PVZEngine;

namespace MVZ2.Options
{
    public class Options
    {
        public Options()
        {
            keyBindings = new KeyBindingOptions();
        }
        public void SetOptionBool(NamespaceID id, bool value)
        {
            boolOptions[id] = value;
        }
        public void SetOptionInt(NamespaceID id, int value)
        {
            intOptions[id] = value;
        }
        public void SetOptionFloat(NamespaceID id, float value)
        {
            floatOptions[id] = value;
        }
        public void SetOptionString(NamespaceID id, string value)
        {
            stringOptions[id] = value;
        }
        public void SetOptionID(NamespaceID id, NamespaceID? value)
        {
            idOptions[id] = value;
        }
        public bool ContainsOptionBool(NamespaceID id)
        {
            return boolOptions.ContainsKey(id);
        }
        public bool ContainsOptionInt(NamespaceID id)
        {
            return intOptions.ContainsKey(id);
        }
        public bool ContainsOptionFloat(NamespaceID id)
        {
            return floatOptions.ContainsKey(id);
        }
        public bool ContainsOptionString(NamespaceID id)
        {
            return stringOptions.ContainsKey(id);
        }
        public bool ContainsOptionID(NamespaceID id)
        {
            return idOptions.ContainsKey(id);
        }
        public bool TryGetOptionBool(NamespaceID id, out bool value)
        {
            return boolOptions.TryGetValue(id, out value);
        }
        public bool TryGetOptionInt(NamespaceID id, out int value)
        {
            return intOptions.TryGetValue(id, out value);
        }
        public bool TryGetOptionFloat(NamespaceID id, out float value)
        {
            return floatOptions.TryGetValue(id, out value);
        }
        public bool TryGetOptionString(NamespaceID id, out string value)
        {
            return stringOptions.TryGetValue(id, out value);
        }
        public bool TryGetOptionID(NamespaceID id, out NamespaceID? value)
        {
            return idOptions.TryGetValue(id, out value);
        }
        public SerializableOptionsV1 ToSerializable()
        {
            return new SerializableOptionsV1()
            {
                keyBindings = keyBindings.ToSerializable(),
                boolOptions = boolOptions.ToDictionary(p => p.Key.ToString(), p => p.Value),
                intOptions = intOptions.ToDictionary(p => p.Key.ToString(), p => p.Value),
                floatOptions = floatOptions.ToDictionary(p => p.Key.ToString(), p => p.Value),
                stringOptions = stringOptions.ToDictionary(p => p.Key.ToString(), p => p.Value),
                idOptions = idOptions.ToDictionary(p => p.Key.ToString(), p => p.Value?.ToString()),
            };
        }
        public void LoadFromSerializableV0(SerializableOptions options)
        {
            if (options == null)
                return;
            if (options.keyBindings != null)
                keyBindings.LoadFromSerializable(options.keyBindings);
            if (options.hpBar != null)
            {
                var hpBar = new HPBarOptions();
                hpBar.LoadFromSerializable(options.hpBar);
                SetOptionBool(LogicOptionItemID.hpBarEnabled, hpBar.enabled);
                SetOptionBool(LogicOptionItemID.hpBarAutoHide, hpBar.autoHide);
                SetOptionInt(LogicOptionItemID.hpBarAmountMode, hpBar.amountMode);
                SetOptionFloat(LogicOptionItemID.hpBarHoverDisplayRange, hpBar.hoverDisplayRange);
            }
            SetOptionBool(LogicOptionItemID.skipTalks, options.skipAllTalks);
            SetOptionBool(LogicOptionItemID.showSponsorNames, options.showSponsorNames);
            SetOptionBool(LogicOptionItemID.blueprintWarnings, !options.blueprintWarningsDisabled);
            SetOptionInt(LogicOptionItemID.commandBlockMode, options.commandBlockMode);
            SetOptionInt(LogicOptionItemID.fpsMode, options.fpsMode);
            SetOptionBool(LogicOptionItemID.showHotkeys, options.showHotkeyIndicators);
            SetOptionBool(LogicOptionItemID.hdrLighting, !options.hdrLightingDisabled);
            SetOptionBool(LogicOptionItemID.heightIndicator, options.heightIndicatorEnabled);
        }
        public void LoadFromSerializableV1(SerializableOptionsV1 options)
        {
            if (options == null)
                return;
            if (options.keyBindings != null)
                keyBindings.LoadFromSerializable(options.keyBindings);
            if (options.boolOptions != null)
            {
                foreach (var pair in options.boolOptions)
                {
                    boolOptions.Add(NamespaceID.ParseStrict(pair.Key), pair.Value);
                }
            }
            if (options.intOptions != null)
            {
                foreach (var pair in options.intOptions)
                {
                    intOptions.Add(NamespaceID.ParseStrict(pair.Key), pair.Value);
                }
            }
            if (options.floatOptions != null)
            {
                foreach (var pair in options.floatOptions)
                {
                    floatOptions.Add(NamespaceID.ParseStrict(pair.Key), pair.Value);
                }
            }
            if (options.stringOptions != null)
            {
                foreach (var pair in options.stringOptions)
                {
                    stringOptions.Add(NamespaceID.ParseStrict(pair.Key), pair.Value);
                }
            }
            if (options.idOptions != null)
            {
                foreach (var pair in options.idOptions)
                {
                    NamespaceID? value = null;
                    if (pair.Value != null)
                    {
                        value = NamespaceID.ParseStrict(pair.Value);
                    }
                    idOptions.Add(NamespaceID.ParseStrict(pair.Key), value);
                }
            }
        }
        public KeyBindingOptions keyBindings;
        public Dictionary<NamespaceID, bool> boolOptions = new();
        public Dictionary<NamespaceID, int> intOptions = new();
        public Dictionary<NamespaceID, float> floatOptions = new();
        public Dictionary<NamespaceID, string> stringOptions = new();
        public Dictionary<NamespaceID, NamespaceID?> idOptions = new();
    }
}
